353	static int input_parpare(string input_path_or_folder, vector<string>& in_list)
354	{
355	    struct stat s_buf;  
356	    stat(input_path_or_folder.c_str(), &s_buf); 
357	    
358	    in_list.clear();
359	    
360	    if(S_ISDIR(s_buf.st_mode))  
361	    {  
362	        if (input_path_or_folder.c_str()[input_path_or_folder.length()-1] != '/') {
363	            input_path_or_folder +=  "/";
364	        }
365	
366	        int i=0;
367	        std::string absolute_path;
368	        std::string file_name;
369	        
370	        struct dirent **namelist = NULL;
371	        int n;
372	        n = scandir(input_path_or_folder.c_str(), &namelist, 0,  alphasort);
373	        for (int k = 0; k < n; k++)
374	        {
375	            //file_name = ptr->d_name;
376	            file_name = namelist[k]->d_name;
377	            std::string ext = file_name.substr(file_name.find_last_of(".") + 1);
378	            transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
379	            if ( ext == "jpg" || ext == "jpeg" || ext == "png" || ext == "pgm" || ext == "bmp" || ext == "ppm") 
380	            {
381	                absolute_path = input_path_or_folder;
382	                absolute_path += file_name;
383	                i++;
384	                in_list.push_back(absolute_path);
385	            }
386	        }
387	        if (namelist != NULL) free(namelist);
388	    }
389	    else {
390	        in_list.push_back(input_path_or_folder);
391	    }
392	
393	    printf("Find input count = %d\n", (int)in_list.size());
394	    return 0;
395	}
